@Component("backupOpertValidator")
public class BackupOpertValidator implements Validator {

	private static final String SOURCE_BASE_DIRECTORY = EgovProperties.getProperty("Globals.SynchrnServerPath");
	private static final String TARGET_BASE_DIRECTORY = EgovProperties.getProperty("Globals.SynchrnServerPath");

	/*
	 * (non-Javadoc)
	 * @see org.springframework.validation.Validator#supports(java.lang.Class)
	 */
    @Override
	public boolean supports(Class<?> clazz) {
        return BackupOpert.class.isAssignableFrom(clazz);
     }

    /*
     * (non-Javadoc)
     * @see org.springframework.validation.Validator#validate(java.lang.Object, org.springframework.validation.Errors)
     */
	@Override
	public void validate(Object obj, Errors errors) {
		// 배치프로그램으로 지정된 값이 파일로 존재하는지 검사한다.
		BackupOpert backupOpert = (BackupOpert) obj;
		File dir = null;
		String srcDir = backupOpert.getBackupOrginlDrctry();
		//KISA 보안약점 조치 (2018-10-29, 윤창원)
		dir = new File(SOURCE_BASE_DIRECTORY + EgovWebUtil.filePathBlackList(srcDir));
		try {
			if (!dir.exists()) {
				errors.rejectValue("backupOrginlDrctry", "errors.backupOrginlDrctry", new Object [] { srcDir },
			    "디렉토리 {0}이  존재하지 않습니다.");
				return ;
			}
			if (!dir.isDirectory()) {
				errors.rejectValue("backupOrginlDrctry", "errors.backupOrginlDrctry", new Object [] { srcDir },
			    "본디렉토리 {0}이 디렉토리가 아닙니다.");
				return ;
			}
		} catch (SecurityException  se) {
			errors.rejectValue("backupOrginlDrctry", "errors.backupOrginlDrctry", new Object [] { srcDir },
		    " 디렉토리 {0}에 접근할 수 없습니다. 파일접근권한을 확인하세요.");
			return ;
		}

		//KISA 보안약점 조치 (2018-10-29, 윤창원)
		String targetDir = EgovStringUtil.isNullToString(backupOpert.getBackupStreDrctry());
		//KISA 보안약점 조치 (2018-10-29, 윤창원)
		dir = new File(TARGET_BASE_DIRECTORY + EgovWebUtil.filePathBlackList(EgovStringUtil.isNullToString(backupOpert.getBackupStreDrctry())));
		try {
			if (!dir.exists()) {
				errors.rejectValue("backupStreDrctry", "errors.backupStreDrctry", new Object [] { targetDir },
			    "디렉토리 {0}이  존재하지 않습니다.");
				return ;
			}
			if (!dir.isDirectory()) {
				errors.rejectValue("backupStreDrctry", "errors.backupStreDrctry", new Object [] { targetDir },
			    "디렉토리 {0}이 디렉토리가 아닙니다.");
				return ;
			}
		} catch (SecurityException  se) {
			errors.rejectValue("backupStreDrctry", "errors.backupStreDrctry", new Object [] { targetDir },
		    " 디렉토리 {0}에 접근할 수 없습니다. 파일접근권한을 확인하세요.");
			return ;
		}

		if ( targetDir.equals(srcDir)) {
			errors.rejectValue("backupStreDrctry", "errors.backupStreDrctry", new Object [] { srcDir, targetDir },
		    "백업원본디렉토리{0}과 백업저장디렉토리 {1}이 같은 값을 가질수 없습니다.");
			return ;
		}

	/**
	 * 백업작업을 등록한다.
	 * @return 리턴URL
	 *
	 * @param backupOpert 등록대상 백업작업model
	 * @param bindingResult	BindingResult
	 * @param model			ModelMap
	 * @param redirectAttributes RedirectAttributes
	 * @exception Exception Exception
	 */
    @RequestMapping("/sym/sym/bak/addBackupOpert.do")
	public String insertBackupOpert(@ModelAttribute("searchVO") BackupOpert searchVO,
			@Valid @ModelAttribute("backupOpert") BackupOpert backupOpert, BindingResult bindingResult,
			ModelMap model, RedirectAttributes redirectAttributes) throws Exception{

    	LOGGER.debug(" 인서트 대상정보 : {}", backupOpert);

	  	// 0. Spring Security 사용자권한 처리
	  	Boolean isAuthenticated = EgovUserDetailsHelper.isAuthenticated();
	  	if(!isAuthenticated) {
	  		redirectAttributes.addAttribute("message", egovMessageSource.getMessage("fail.common.login"));
	      	return "redirect:/uat/uia/egovLoginUsr.do";
	  	}

		//로그인 객체 선언
		LoginVO loginVO = (LoginVO)EgovUserDetailsHelper.getAuthenticatedUser();

		backupOpertValidator.validate(backupOpert, bindingResult);
	  	if (bindingResult.hasErrors()){
	  		referenceData(model);
	  		return "egovframework/com/sym/sym/bak/EgovBackupOpertRegist";
		}

		backupOpert.setBackupOpertId(idgenService.getNextStringId());
		//아이디 설정
		backupOpert.setLastUpdusrId(loginVO == null ? "" : EgovStringUtil.isNullToString(loginVO.getUniqId()));
		backupOpert.setFrstRegisterId(loginVO == null ? "" : EgovStringUtil.isNullToString(loginVO.getUniqId()));

		egovBackupOpertService.insertBackupOpert(backupOpert);

		// 배치스케줄러에 스케줄정보반영
		BackupOpert target = egovBackupOpertService.selectBackupOpert(backupOpert);
		backupScheduler.insertBackupOpert(target);

        //Exception 없이 진행시 등록성공메시지
        model.addAttribute("resultMsg", "success.common.insert");

	  	return "forward:/sym/sym/bak/getBackupOpertList.do";
	}

